// Thresholds for Indicator Logic
export const INDICATOR_THRESHOLDS = {
  // Valuation
  PE_DISCOUNT_PERCENT: 10, // Check if Current PE is 10% lower than Average

  // Volume
  VOLUME_SPIKE_PERCENT: 60, // Check if Day Vol is 60% higher than average

  // Price Action
  LOW_52W_THRESHOLD: 10, // Check if price is within 10% of 52W Low

  // Returns (Underperformance checks)
  RETURN_1Y_MAX: 5,   // If 1Y return <= 5%
  RETURN_2Y_MAX: 10,  // If 2Y return <= 10%
  RETURN_5Y_MAX: 20   // If 5Y return <= 20%
};

// Insight Text Templates
export const INSIGHT_TEXT_TEMPLATES = {
  VALUATION_ATTRACTIVE: "Stock is trading at an attractive valuation. Current PE ({current}) is {diff}% below the historical average ({average}).",
  VOLUME_SPIKE: "High buying interest detected. Daily volume ({day}) is {percent}% higher than the {period} average.",
  NEAR_52W_LOW: "Stock is trading near support levels, currently {percent}% from its 52-week low.",
  LOW_RETURNS_1Y: "Stock has underperformed with only {value}% returns over the last 1 year.",
  LOW_RETURNS_2Y: "Long-term consolidation detected. 2-year returns are {value}%, below the {threshold}% threshold.",
  LOW_RETURNS_5Y: "Significant long-term underperformance. 5-year returns are {value}%, below the {threshold}% threshold.",
  TRADING_BELOW_DMA: "Bearish Trend: Stock is trading below its {period} ({value}).",
  TRADING_ABOVE_DMA: "Bullish Trend: Stock is trading above its {period} ({value})."
};

import { INDICATOR_THRESHOLDS, INSIGHT_TEXT_TEMPLATES } from "../types/constants";

// --- Types based on provided JSON structures ---

interface PETile {
  title: string;
  label: string;
  value: string;
  message: string;
}

interface PEJsonData {
  tiles: PETile[];
}

interface TechnicalParameter {
  name: string;
  value: number;
  insight: string | null;
  color: string;
  description: string | null;
}

interface VolumeTableRow {
  0: string; // Period Name (Day, Week, etc)
  1: number; // Volume
  2: number; // Delivery %
  3: number; // Delivery Volume
}

interface PriceAnalysisItem {
  name: string; // "1 Day", "1 Year", etc.
  changePercent: number;
  changePercentSafe?: number;
}

interface TechnicalJsonData {
  body: {
    parameters: {
      current_price: number;
      price_insight?: Array<{
          param: string; // "year_low"
          value: number;
      }>;
      price_analysis?: PriceAnalysisItem[];
      sma_parameters?: TechnicalParameter[];
      ema_parameters?: TechnicalParameter[];
      volume_analysis?: {
        tableData?: VolumeTableRow[];
      };
    };
  };
}

interface ProcessedInsight {
  status: 'triggered' | 'ignored';
  text?: string;
  data?: any;
}

// --- Helper: Clean Number String ---
const parseNumber = (str: string): number => {
  if (!str) return 0;
  // Remove commas, text, newlines, percentage signs
  const clean = str.replace(/,/g, '').replace(/[^\d.-]/g, '');
  return parseFloat(clean) || 0;
};

// --- 1. Valuation Analysis (PE) ---
// Evaluate Current PE value against Average PE Value. 
// If it is below the threshold of 10%. Then Consider this and return the Stock with a text saying the same.

export const evaluateValuation = (data: PEJsonData): ProcessedInsight => {
  if (!data?.tiles) return { status: 'ignored' };

  const currentPeTile = data.tiles.find(t => t.label.toLowerCase() === "current pe");
  const averagePeTile = data.tiles.find(t => t.label.toLowerCase() === "average pe");

  if (!currentPeTile || !averagePeTile) return { status: 'ignored' };

  const currentPE = parseNumber(currentPeTile.value);
  const averagePE = parseNumber(averagePeTile.value);

  if (averagePE === 0) return { status: 'ignored' };

  // Calculate percentage difference relative to average
  // Formula: Is Current PE < Average PE by X%? 
  // (Average - Current) / Average * 100
  const diffPercent = ((averagePE - currentPE) / averagePE) * 100;

  if (currentPE < averagePE && diffPercent >= INDICATOR_THRESHOLDS.PE_DISCOUNT_PERCENT) {
    const text = INSIGHT_TEXT_TEMPLATES.VALUATION_ATTRACTIVE
      .replace('{current}', currentPE.toFixed(1))
      .replace('{diff}', diffPercent.toFixed(1))
      .replace('{average}', averagePE.toFixed(1));

    return {
      status: 'triggered',
      text,
      data: { currentPE, averagePE, diffPercent }
    };
  }

  return { status: 'ignored' };
};

// --- 2. Volume Analysis ---
// If daily volume is above threshold of 60% or above the weekly or monthly average

export const evaluateVolume = (data: TechnicalJsonData): ProcessedInsight => {
  const params = data?.body?.parameters;
  const volumeTable = params?.volume_analysis?.tableData;

  if (!volumeTable || !Array.isArray(volumeTable)) return { status: 'ignored' };

  const dayRow = volumeTable.find(row => row[0] === "Day");
  // Assuming Weekly/Monthly rows exist and index 1 contains the volume metric (Avg or Total)
  const weekRow = volumeTable.find(row => row[0] === "Week");
  const monthRow = volumeTable.find(row => row[0] === "1 Month");

  if (!dayRow) return { status: 'ignored' };

  const dayVol = dayRow[1];

  // Helper to check spike
  const checkSpike = (periodRow: VolumeTableRow | undefined, periodName: string): string | null => {
    if (!periodRow) return null;
    const periodVol = periodRow[1];
    if (periodVol === 0) return null;

    const percentDiff = ((dayVol - periodVol) / periodVol) * 100;

    if (dayVol > periodVol && percentDiff >= INDICATOR_THRESHOLDS.VOLUME_SPIKE_PERCENT) {
      return INSIGHT_TEXT_TEMPLATES.VOLUME_SPIKE
        .replace('{day}', (dayVol / 100000).toFixed(2) + 'L')
        .replace('{percent}', percentDiff.toFixed(0))
        .replace('{period}', periodName);
    }
    return null;
  };

  const weekInsight = checkSpike(weekRow, "weekly");
  if (weekInsight) return { status: 'triggered', text: weekInsight };

  const monthInsight = checkSpike(monthRow, "monthly");
  if (monthInsight) return { status: 'triggered', text: monthInsight };

  return { status: 'ignored' };
};

// --- 3. 52 Week Low Analysis ---
// finding if stock is at threshold of >=10% from 52 week low (assuming "from" means above/near)

export const evaluate52WeekLow = (data: TechnicalJsonData): ProcessedInsight => {
  const params = data?.body?.parameters;
  const currentPrice = params?.current_price;

  // Try to find year_low in insights
  const lowInsight = params?.price_insight?.find(i => i.param === "year_low");
  let yearLowValue = lowInsight ? lowInsight.value : 0;

  // Fallback to price_analysis "1 Year" low if insight missing
  if (!yearLowValue && params?.price_analysis) {
      const oneYear = params.price_analysis.find(i => i.name === "1 Year");
      // @ts-ignore - assuming 'low' exists in raw json even if not fully typed in basic interface
      if (oneYear && oneYear.low) yearLowValue = oneYear.low;
  }

  if (!currentPrice || !yearLowValue) return { status: 'ignored' };

  // Calculate distance from low
  const distanceFromLowPercent = ((currentPrice - yearLowValue) / yearLowValue) * 100;

  // Check if it is within the threshold (e.g., has it recovered less than 10%? or is it near?)
  // Prompt: "threshold of >=10% from 52 week low". 
  // Interpretation: If price has moved >= 10% it might be recovering, OR
  // Interpretation: If price is WITHIN 10% (<=10%). 
  // Usually "Near 52W Low" implies it hasn't run away yet.
  // Using constant logic: LOW_52W_THRESHOLD (10). 
  // We'll assume trigger if it is *within* 10% of the low (i.e. <= 10% above low).

  if (distanceFromLowPercent <= INDICATOR_THRESHOLDS.LOW_52W_THRESHOLD && distanceFromLowPercent >= 0) {
    const text = INSIGHT_TEXT_TEMPLATES.NEAR_52W_LOW
      .replace('{percent}', distanceFromLowPercent.toFixed(1));

    return { status: 'triggered', text, data: { currentPrice, yearLowValue } };
  }

  return { status: 'ignored' };
};

// --- 4. Returns Analysis ---
// is the price near 1 Year/2 Years./3 year if % is <=10 for 2 year, <=5 for 1 year or <=20 for 5Y

export const evaluateReturns = (data: TechnicalJsonData): ProcessedInsight => {
  const analysis = data?.body?.parameters?.price_analysis;
  if (!analysis || !Array.isArray(analysis)) return { status: 'ignored' };

  const getReturn = (period: string) => analysis.find(i => i.name === period);

  const r1y = getReturn("1 Year");
  const r2y = getReturn("2 Year") || getReturn("2 Years");
  const r5y = getReturn("5 Year") || getReturn("5 Years");

  const insights: string[] = [];

  // Check 1 Year
  if (r1y) {
    const val = r1y.changePercentSafe ?? r1y.changePercent;
    if (val !== undefined && val <= INDICATOR_THRESHOLDS.RETURN_1Y_MAX) {
       insights.push(INSIGHT_TEXT_TEMPLATES.LOW_RETURNS_1Y.replace('{value}', val.toFixed(1)));
    }
  }

  // Check 2 Year
  if (r2y) {
    const val = r2y.changePercentSafe ?? r2y.changePercent;
    if (val !== undefined && val <= INDICATOR_THRESHOLDS.RETURN_2Y_MAX) {
       insights.push(INSIGHT_TEXT_TEMPLATES.LOW_RETURNS_2Y
         .replace('{value}', val.toFixed(1))
         .replace('{threshold}', String(INDICATOR_THRESHOLDS.RETURN_2Y_MAX))
       );
    }
  }

  // Check 5 Year
  if (r5y) {
    const val = r5y.changePercentSafe ?? r5y.changePercent;
    if (val !== undefined && val <= INDICATOR_THRESHOLDS.RETURN_5Y_MAX) {
       insights.push(INSIGHT_TEXT_TEMPLATES.LOW_RETURNS_5Y
         .replace('{value}', val.toFixed(1))
         .replace('{threshold}', String(INDICATOR_THRESHOLDS.RETURN_5Y_MAX))
       );
    }
  }

  if (insights.length > 0) {
    return {
      status: 'triggered',
      text: insights.join(" "), // Return combined text if multiple match
    };
  }

  return { status: 'ignored' };
};

// --- 5. Technical Indicators (DMA) ---
// If Current price price is below 50 DMA or 200 DMA.

export const evaluateDMA = (data: TechnicalJsonData): ProcessedInsight => {
  const params = data?.body?.parameters;
  if (!params) return { status: 'ignored' };

  const currentPrice = params.current_price;
  const smas = params.sma_parameters;

  if (!currentPrice || !smas) return { status: 'ignored' };

  const getSMA = (name: string) => smas.find(s => s.name === name);
  const sma50 = getSMA("50 Day");
  const sma200 = getSMA("200 Day");

  const insights: string[] = [];

  if (sma50 && currentPrice < sma50.value) {
    insights.push(INSIGHT_TEXT_TEMPLATES.TRADING_BELOW_DMA
        .replace('{period}', '50 DMA')
        .replace('{value}', sma50.value.toFixed(1))
    );
  }

  if (sma200 && currentPrice < sma200.value) {
    insights.push(INSIGHT_TEXT_TEMPLATES.TRADING_BELOW_DMA
        .replace('{period}', '200 DMA')
        .replace('{value}', sma200.value.toFixed(1))
    );
  }

  if (insights.length > 0) {
    return {
      status: 'triggered',
      text: insights.join(" ")
    };
  }

  return { status: 'ignored' };
};

// --- Main Processor Entry Point (Example Usage) ---
// This function aggregates logic based on indicator type provided in the main app
export const processIndicatorData = (indicatorType: string, jsonData: any): ProcessedInsight => {
  switch(indicatorType) {
    case 'PE':
    case 'DetailledPE': 
        // Assuming Standard PE tile structure for both for now, or adapt as needed
        return evaluateValuation(jsonData);

    case 'Technical':
        // Runs all technical checks and consolidates
        const vol = evaluateVolume(jsonData);
        const low52 = evaluate52WeekLow(jsonData);
        const returns = evaluateReturns(jsonData);
        const dma = evaluateDMA(jsonData);

        // Priority logic or concatenation
        const texts = [vol.text, low52.text, returns.text, dma.text].filter(Boolean);

        if (texts.length > 0) {
           return { status: 'triggered', text: texts.join("\n") };
        }
        return { status: 'ignored' };

    default:
        return { status: 'ignored' };
  }
};

