// --- Main Processor Entry Point ---
export const processIndicatorData = (symbol: string, indicatorType: string, jsonData: any): ProcessedInsight => {
  switch(indicatorType) {
    case 'PE':
    case 'DetailledPE': 
        return evaluateValuation(symbol, jsonData);

    // Note: 'Technical' usually refers to price parameters, 
    // but the new Volume/Delivery JSON might come under a specific indicator name 
    // or overlay on top of 'Technical' if the source provides it differently.
    // Based on the prompt, if the data has "volumes" array, we use evaluateVolume.

    case 'Technical':
        // Detect data structure
        if (jsonData && Array.isArray(jsonData.volumes) && Array.isArray(jsonData.delivery)) {
            return evaluateVolume(symbol, jsonData);
        }

        // Fallback to standard technical checks
        const low52 = evaluate52WeekLow(symbol, jsonData);
        const returns = evaluateReturns(symbol, jsonData);
        const dma = evaluateDMA(symbol, jsonData);

        const texts = [low52.text, returns.text, dma.text].filter(Boolean);

        if (texts.length > 0) {
           return { 
               status: 'triggered', 
               text: texts.join("\n"),
               data: { symbol }
           };
        }
        return { status: 'ignored', data: { symbol } };

    default:
        return { status: 'ignored', data: { symbol } };
  }
};

